import { Component, OnChanges, SimpleChanges, computed, inject, input, output } from '@angular/core';
import { FormControl, FormsModule, ReactiveFormsModule, Validators } from '@angular/forms';
import { CommonModule } from '@angular/common';
import { ButtonComponent } from '../../dump/button/button';
import { InputComponent } from '../../dump/input/input';
import { BIOMES } from '../../../utils/interfaces/biomes';
import { GameService } from '../../../services/game/game';

const MAX_HEIGHT = 3000;
const WATER_HEIGHT = BIOMES.sea.threshold * MAX_HEIGHT;

@Component({
  selector: 'info',
  imports: [CommonModule, FormsModule, ReactiveFormsModule, ButtonComponent, InputComponent],
  standalone: true,
  templateUrl: './info.html',
})
export class InfoComponent implements OnChanges {
  protected readonly gameService = inject(GameService);

  public readonly seed = input.required<number>();
  public readonly regenerate = output<number>();

  protected readonly seedFormControl = new FormControl<number>(0, [Validators.required, Validators.minLength(1), Validators.maxLength(9)]);

  protected readonly pointHeight = computed(() => {
    const { posX, posY } = this.gameService.cameraPos();
    const point = this.gameService.terrain()?.[Math.round(posY)]?.[Math.round(posX)];
    const height = point?.height ?? 0;

    return height * (MAX_HEIGHT + WATER_HEIGHT) - WATER_HEIGHT;
  });

  public ngOnChanges(changes: SimpleChanges<InfoComponent>) {
    if (changes.seed) {
      this.seedFormControl.setValue(this.seed());
    }
  }

  protected regenerateMap() {
    const newSeed = this.seedFormControl.value;
    if (newSeed) {
      // eslint-disable-next-line @typescript-eslint/no-unnecessary-type-conversion
      this.regenerate.emit(Number(newSeed));
    }
  }
}
