import { Component, inject } from '@angular/core';
import { WeatherComponent } from '../../components/weather/weather';
import { GeneratorService } from '../../services/generator';
import { HeaderComponent } from '../../components/dump/header/header';
import { ButtonComponent } from '../../components/dump/button/button';
import { RouterLink } from '@angular/router';
import { SidePanelComponent } from '../../components/dump/side-panel/side-panel';
import { MinimapComponent } from '../../components/smart/minimap/minimap';
import { InfoComponent } from '../../components/smart/info/info';
import { GameMapComponent } from '../../components/smart/game-map/game-map';
import { MAX_ZOOM, MIN_ZOOM } from '../../services/_params';

@Component({
  selector: 'game-page',
  imports: [MinimapComponent, InfoComponent, WeatherComponent, HeaderComponent, ButtonComponent, RouterLink, SidePanelComponent, GameMapComponent],
  standalone: true,
  templateUrl: './generator.html',
})
export class GeneratorPage {
  protected readonly generatorService = inject(GeneratorService);

  protected readonly maxZoom = MAX_ZOOM;
  protected readonly minZoom = MIN_ZOOM;

  public constructor() {
    this.regenerateMap(0);
  }

  protected regenerateMap(seed: number) {
    const newSeed = seed === this.generatorService.seed() ? Math.floor(Math.random() * 1e9) : seed;
    this.generatorService.seed.set(newSeed);
  }
}
